@@ -0,0 +1,508 @@
+package main
+
+import (
+	"context"
+	"errors"
+	"fmt"
+	"owldb/skiplist"
+)
+
+// DocMeta holds metadata for a document.
+type DocMeta struct {
+	CreatedBy      string  `json:"createdBy"`
+	CreatedAt      int64   `json:"createdAt"`
+	LastModifiedBy string  `json:"lastModifiedBy"`
+	LastModifiedAt int64   `json:"lastModifiedAt"`
+}
+
+// Document holds the raw JSON content and metadata for a stored document.
+type Document struct {
+	Content []byte
+	Meta    DocMeta
+	// Collections associated with this document (key = collection name)
+	Collections *skiplist.SkipList[string, *Collection]
+}
+
+// Collection holds the documents indexed by name.
+type Collection struct {
+	Name string
+	Docs *skiplist.SkipList[string, *Document]
+}
+
+// DBStore is the top-level store holding all databases.
+type DBStore struct {
+	databases *skiplist.SkipList[string, *Collection]
+}
+
+// NewDBStore creates a new empty DBStore.
+func NewDBStore() *DBStore {
+	return &DBStore{
+		databases: skiplist.New[string, *Collection](),
+	}
+}
+
+// newDocument creates a new Document with the given content and metadata.
+func newDocument(content []byte, meta DocMeta) *Document {
+	return &Document{
+		Content:     content,
+		Meta:        meta,
+		Collections: skiplist.New[string, *Collection](),
+	}
+}
+
+// newCollection creates a new empty Collection with the given name.
+func newCollection(name string) *Collection {
+	return &Collection{
+		Name: name,
+		Docs: skiplist.New[string, *Document](),
+	}
+}
+
+// ErrExists is returned when trying to create a resource that already exists.
+var ErrExists = errors.New("already exists")
+
+// ErrNotFound is returned when a resource is not found.
+var ErrNotFound = errors.New("not found")
+
+// ErrNoOverwrite is returned when a PUT with nooverwrite mode would overwrite.
+var ErrNoOverwrite = errors.New("document already exists (nooverwrite mode)")
+
+// CreateDatabase creates a new database with the given name.
+// Returns ErrExists if the database already exists.
+func (store *DBStore) CreateDatabase(name string) error {
+	_, err := store.databases.Upsert(name, func(k string, curr *Collection, exists bool) (*Collection, error) {
+		if exists {
+			return curr, ErrExists
+		}
+		return newCollection(k), nil
+	})
+	return err
+}
+
+// DeleteDatabase removes a database by name.
+// Returns ErrNotFound if the database doesn't exist.
+func (store *DBStore) DeleteDatabase(name string) (*Collection, error) {
+	db, found := store.databases.Remove(name)
+	if !found {
+		return nil, ErrNotFound
+	}
+	return db, nil
+}
+
+// GetDatabase returns the collection for a database by name.
+func (store *DBStore) GetDatabase(name string) (*Collection, bool) {
+	return store.databases.Find(name)
+}
+
+// parsedPath holds a parsed URL path segments.
+type parsedPath struct {
+	segments    []string
+	hasTrailing bool
+}
+
+// isDatabase returns true if this path refers to a database (only one segment).
+func (p parsedPath) isDatabase() bool {
+	return len(p.segments) == 1 && p.hasTrailing
+}
+
+// isCollection returns true if this path refers to a collection.
+func (p parsedPath) isCollection() bool {
+	return p.hasTrailing && len(p.segments) >= 3
+}
+
+// isDocument returns true if this path refers to a document.
+func (p parsedPath) isDocument() bool {
+	return !p.hasTrailing && len(p.segments) >= 2
+}
+
+// dbName returns the database name.
+func (p parsedPath) dbName() string {
+	if len(p.segments) > 0 {
+		return p.segments[0]
+	}
+	return ""
+}
+
+// navigateToCollection navigates through the database hierarchy to find the target collection.
+// The collection is the container that holds the target document or collection.
+// For a path like /db/doc1/col1/doc2/col2/, returns the col2 Collection.
+// For a path like /db/doc1/, returns the database's root collection "db".
+// For a path like /db/, returns the database collection itself.
+func (store *DBStore) navigateToParentCollection(p parsedPath) (*Collection, string, error) {
+	segs := p.segments
+
+	if len(segs) == 0 {
+		return nil, "", ErrNotFound
+	}
+
+	// Get the database
+	dbCol, found := store.databases.Find(segs[0])
+	if !found {
+		return nil, "", ErrNotFound
+	}
+
+	if len(segs) == 1 {
+		// It's the database itself
+		return dbCol, segs[0], nil
+	}
+
+	// Navigate through doc/col pairs
+	// segs[0] = db name
+	// segs[1] = doc name in db
+	// segs[2] = collection name in doc
+	// segs[3] = doc name in collection
+	// etc.
+	currentCol := dbCol
+	i := 1
+	for i < len(segs)-1 {
+		docName := segs[i]
+		doc, found := currentCol.Docs.Find(docName)
+		if !found {
+			return nil, "", ErrNotFound
+		}
+		i++
+		if i >= len(segs)-1 {
+			// Next is the target
+			break
+		}
+		colName := segs[i]
+		col, found := doc.Collections.Find(colName)
+		if !found {
+			return nil, "", ErrNotFound
+		}
+		currentCol = col
+		i++
+	}
+
+	// At this point, currentCol is the parent collection and segs[len-1] is the target name
+	return currentCol, segs[len(segs)-1], nil
+}
+
+// navigateToDocument navigates to find a document by its parsed path.
+func (store *DBStore) navigateToDocument(p parsedPath) (*Document, *Collection, string, error) {
+	if !p.isDocument() {
+		return nil, nil, "", fmt.Errorf("path is not a document")
+	}
+
+	parentCol, docName, err := store.navigateToParentCollection(p)
+	if err != nil {
+		return nil, nil, "", err
+	}
+
+	doc, found := parentCol.Docs.Find(docName)
+	if !found {
+		return nil, nil, "", ErrNotFound
+	}
+
+	return doc, parentCol, docName, nil
+}
+
+// navigateToCollection navigates to find a collection by its parsed path.
+func (store *DBStore) navigateToCollection(p parsedPath) (*Collection, error) {
+	if p.isDatabase() {
+		db, found := store.databases.Find(p.dbName())
+		if !found {
+			return nil, ErrNotFound
+		}
+		return db, nil
+	}
+
+	if !p.isCollection() {
+		return nil, fmt.Errorf("path is not a collection")
+	}
+
+	segs := p.segments
+	// For a collection path like /db/doc/col/, segs = ["db", "doc", "col"]
+	// We need to navigate to the document that owns this collection
+
+	dbCol, found := store.databases.Find(segs[0])
+	if !found {
+		return nil, ErrNotFound
+	}
+
+	if len(segs) < 3 {
+		return nil, ErrNotFound
+	}
+
+	// Navigate to the owning document, then find the collection
+	currentCol := dbCol
+	i := 1
+	for i < len(segs)-1 {
+		docName := segs[i]
+		doc, found := currentCol.Docs.Find(docName)
+		if !found {
+			return nil, ErrNotFound
+		}
+		i++
+		if i >= len(segs) {
+			break
+		}
+		colName := segs[i]
+		if i == len(segs)-1 {
+			// This is the target collection
+			col, found := doc.Collections.Find(colName)
+			if !found {
+				return nil, ErrNotFound
+			}
+			return col, nil
+		}
+		col, found := doc.Collections.Find(colName)
+		if !found {
+			return nil, ErrNotFound
+		}
+		currentCol = col
+		i++
+	}
+
+	return nil, ErrNotFound
+}
+
+// getQueryCollection returns the Collection for a GET/subscribe query.
+// Works for both database paths (/db/) and collection paths (/db/doc/col/).
+func (store *DBStore) getQueryCollection(p parsedPath) (*Collection, error) {
+	return store.navigateToCollection(p)
+}
+
+// PutDocument creates or updates a document at the given path.
+// The check function is called to determine the new document content.
+// Returns (true, doc, nil) if updated, (false, doc, nil) if created.
+func (store *DBStore) PutDocument(p parsedPath, content []byte, meta DocMeta, noOverwrite bool) (updated bool, doc *Document, err error) {
+	if !p.isDocument() {
+		return false, nil, fmt.Errorf("path is not a document")
+	}
+
+	segs := p.segments
+	if len(segs) == 0 {
+		return false, nil, ErrNotFound
+	}
+
+	// Get the database
+	dbCol, found := store.databases.Find(segs[0])
+	if !found {
+		return false, nil, ErrNotFound
+	}
+
+	// Navigate to the parent collection
+	// For path /db/doc, we PUT into dbCol directly
+	// For path /db/doc1/col/doc2, navigate to col then put
+	parentCol, err := store.getParentCollectionForPut(segs, dbCol)
+	if err != nil {
+		return false, nil, err
+	}
+
+	docName := segs[len(segs)-1]
+	var resultDoc *Document
+
+	updated, err = parentCol.Docs.Upsert(docName, func(k string, curr *Document, exists bool) (*Document, error) {
+		if exists && noOverwrite {
+			return curr, ErrNoOverwrite
+		}
+		var newMeta DocMeta
+		if exists {
+			// Keep original createdBy and createdAt
+			newMeta = DocMeta{
+				CreatedBy:      curr.Meta.CreatedBy,
+				CreatedAt:      curr.Meta.CreatedAt,
+				LastModifiedBy: meta.LastModifiedBy,
+				LastModifiedAt: meta.LastModifiedAt,
+			}
+		} else {
+			newMeta = meta
+		}
+		d := &Document{
+			Content:     content,
+			Meta:        newMeta,
+			Collections: skiplist.New[string, *Collection](),
+		}
+		if exists {
+			// Preserve existing collections
+			d.Collections = curr.Collections
+		}
+		resultDoc = d
+		return d, nil
+	})
+	if err != nil {
+		return false, nil, err
+	}
+
+	return updated, resultDoc, nil
+}
+
+// getParentCollectionForPut navigates to the parent collection for a PUT operation.
+func (store *DBStore) getParentCollectionForPut(segs []string, dbCol *Collection) (*Collection, error) {
+	if len(segs) <= 2 {
+		// Document directly in database
+		return dbCol, nil
+	}
+
+	// Navigate through doc/col/doc/col pairs
+	// segs[0] = db, segs[1..n-2] = alternating doc/col, segs[n-1] = target doc
+	currentCol := dbCol
+	i := 1
+	for i < len(segs)-1 {
+		docName := segs[i]
+		doc, found := currentCol.Docs.Find(docName)
+		if !found {
+			return nil, ErrNotFound
+		}
+		i++
+		if i >= len(segs)-1 {
+			break
+		}
+		colName := segs[i]
+		col, found := doc.Collections.Find(colName)
+		if !found {
+			return nil, ErrNotFound
+		}
+		currentCol = col
+		i++
+	}
+	return currentCol, nil
+}
+
+// DeleteDocument removes a document at the given path.
+// Returns the deleted document, ErrNotFound if it doesn't exist.
+func (store *DBStore) DeleteDocument(p parsedPath) (*Document, error) {
+	if !p.isDocument() {
+		return nil, fmt.Errorf("path is not a document")
+	}
+
+	segs := p.segments
+	if len(segs) == 0 {
+		return nil, ErrNotFound
+	}
+
+	dbCol, found := store.databases.Find(segs[0])
+	if !found {
+		return nil, ErrNotFound
+	}
+
+	parentCol, err := store.getParentCollectionForPut(segs, dbCol)
+	if err != nil {
+		return nil, err
+	}
+
+	docName := segs[len(segs)-1]
+	doc, removed := parentCol.Docs.Remove(docName)
+	if !removed {
+		return nil, ErrNotFound
+	}
+	return doc, nil
+}
+
+// CreateCollection creates a collection at the given path.
+// For a path like /db/doc/col/, creates "col" under doc.
+// For a path like /db/, creates the database (handled by CreateDatabase).
+func (store *DBStore) CreateCollection(p parsedPath) error {
+	if p.isDatabase() {
+		return store.CreateDatabase(p.dbName())
+	}
+
+	if !p.isCollection() {
+		return fmt.Errorf("path is not a collection")
+	}
+
+	segs := p.segments
+	// segs = ["db", "doc", "col"] for /db/doc/col/
+	// We need to navigate to the document owning the collection
+
+	dbCol, found := store.databases.Find(segs[0])
+	if !found {
+		return ErrNotFound
+	}
+
+	// Navigate to the parent document
+	currentCol := dbCol
+	i := 1
+	for i < len(segs)-1 {
+		docName := segs[i]
+		doc, found := currentCol.Docs.Find(docName)
+		if !found {
+			return ErrNotFound
+		}
+		i++
+		if i >= len(segs)-1 {
+			// This doc owns the target collection
+			colName := segs[i]
+			_, err := doc.Collections.Upsert(colName, func(k string, curr *Collection, exists bool) (*Collection, error) {
+				if exists {
+					return curr, ErrExists
+				}
+				return newCollection(k), nil
+			})
+			return err
+		}
+		colName := segs[i]
+		col, found := doc.Collections.Find(colName)
+		if !found {
+			return ErrNotFound
+		}
+		currentCol = col
+		i++
+	}
+
+	return ErrNotFound
+}
+
+// DeleteCollection removes a collection at the given path.
+func (store *DBStore) DeleteCollection(p parsedPath) (*Collection, error) {
+	if p.isDatabase() {
+		return store.DeleteDatabase(p.dbName())
+	}
+
+	if !p.isCollection() {
+		return nil, fmt.Errorf("path is not a collection")
+	}
+
+	segs := p.segments
+	// segs = ["db", "doc", "col"] for /db/doc/col/
+
+	dbCol, found := store.databases.Find(segs[0])
+	if !found {
+		return nil, ErrNotFound
+	}
+
+	currentCol := dbCol
+	i := 1
+	for i < len(segs)-1 {
+		docName := segs[i]
+		doc, found := currentCol.Docs.Find(docName)
+		if !found {
+			return nil, ErrNotFound
+		}
+		i++
+		if i >= len(segs)-1 {
+			colName := segs[i]
+			col, removed := doc.Collections.Remove(colName)
+			if !removed {
+				return nil, ErrNotFound
+			}
+			return col, nil
+		}
+		colName := segs[i]
+		col, found := doc.Collections.Find(colName)
+		if !found {
+			return nil, ErrNotFound
+		}
+		currentCol = col
+		i++
+	}
+
+	return nil, ErrNotFound
+}
+
+// QueryCollection returns all documents in a collection with optional interval filtering.
+// interval = "" returns all documents.
+// interval = "[low,high]" returns documents with keys >= low and <= high.
+// interval = "[low,]" returns documents with keys >= low.
+// interval = "[,high]" returns documents with keys <= high.
+func QueryCollection(ctx context.Context, col *Collection, low string, high string, hasLow bool, hasHigh bool) ([]skiplist.Pair[string, *Document], error) {
+	if !hasLow && !hasHigh {
+		return col.Docs.QueryAll(ctx)
+	} else if hasLow && !hasHigh {
+		return col.Docs.QueryFrom(ctx, low)
+	} else if !hasLow && hasHigh {
+		return col.Docs.QueryTo(ctx, high)
+	}
+	return col.Docs.Query(ctx, low, high)
+}
